        new Recipe { Id = 6, Title = "Tiramisu", Category = "Desserts", Ingredients = "6 egg yolks\n¾ cup sugar\n500g mascarpone\n2 cups espresso (cooled)\n3 tbsp coffee liqueur\n24 ladyfinger biscuits\nCocoa powder", Steps = "1. Whisk egg yolks and sugar until thick and pale.\n2. Fold in mascarpone until smooth.\n3. Mix espresso with coffee liqueur.\n4. Dip ladyfingers briefly in coffee mixture.\n5. Layer biscuits and cream in a dish, repeat.\n6. Refrigerate 4 hours, dust with cocoa before serving." },
