arguments.new_str:
@page "/"

<PageTitle>RecipeHub - Recipe Sharing Community</PageTitle>

<h1>Welcome to RecipeHub 🍳</h1>
<p class="lead">Discover and share delicious recipes with our community.</p>

<h2>Browse by Category</h2>
<div class="row">
    @foreach (var category in Categories)
    {
        <div class="col-md-3 mb-4">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h4 class="card-title">@GetEmoji(category) @category</h4>
                    <a href="recipes/@category.ToLower()" class="btn btn-primary mt-2">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private List<string> Categories = new();

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private string GetEmoji(string category) => category switch
    {
        "Breakfast" => "🥞",
        "Lunch" => "🥗",
        "Dinner" => "🍝",
        "Desserts" => "🍪",
        _ => "🍽️"
    };
}

