arguments.file_text:
@page "/recipes"
@page "/recipes/{Category}"

<PageTitle>Recipes - @(Category ?? "All Categories")</PageTitle>

<h1>@GetEmoji(Category) @(Category ?? "All Recipes")</h1>

@if (string.IsNullOrEmpty(Category))
{
    <p>Select a category to browse recipes:</p>
    <ul>
        @foreach (var cat in RecipeService.GetCategories())
        {
            <li><a href="recipes/@cat.ToLower()">@cat</a></li>
        }
    </ul>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/recipes">Recipes</a></li>
            <li class="breadcrumb-item active">@Category</li>
        </ol>
    </nav>

    @if (Recipes.Any())
    {
        <div class="row">
            @foreach (var recipe in Recipes)
            {
                <div class="col-md-4 mb-4">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text text-muted">
                                @if (recipe.RatingCount > 0)
                                {
                                    <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                                }
                                else
                                {
                                    <span>No ratings yet</span>
                                }
                            </p>
                            <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
    else
    {
        <p>No recipes found in this category.</p>
    }
}

@code {
    [Parameter] public string? Category { get; set; }
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

