toolArgs.file_text:
@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

@if (Recipe == null)
{
    <p>Recipe not found.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/recipes/@Recipe.Category.ToLower()">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@Recipe.Category</span>

    <StarRating RecipeId="@Recipe.Id" CurrentAverage="@Recipe.AverageRating" RatingCount="@Recipe.RatingCount" />

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            @* Strip leading number prefix like "1. " *@
            var text = System.Text.RegularExpressions.Regex.Replace(step, @"^\d+\.\s*", "");
            <li>@text</li>
        }
    </ol>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeHub.Models.Recipe? Recipe;

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer

<div class="my-3 p-3 border rounded">
    <h5>Rate this recipe</h5>
    <div class="d-flex align-items-center gap-2">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button class="btn btn-link p-0 fs-4 text-decoration-none"
                    @onclick="() => Rate(star)"
                    title="Rate @star stars">
                @(star <= SelectedRating ? "★" : "☆")
            </button>
        }
        @if (SelectedRating > 0)
        {
            <span class="text-success ms-2">You rated @SelectedRating star@(SelectedRating > 1 ? "s" : "")!</span>
        }
    </div>
    <small class="text-muted">
        @if (RatingCount > 0)
        {
            <span>Average: @CurrentAverage.ToString("F1") ⭐ (@RatingCount ratings)</span>
        }
        else
        {
            <span>Be the first to rate!</span>
        }
    </small>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int RatingCount { get; set; }
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private int SelectedRating;

    private void Rate(int stars)
    {
        SelectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);

        var recipe = RecipeService.GetById(RecipeId);
        if (recipe != null)
        {
            CurrentAverage = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}

