toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted! 🎉</h4>
        <p>Your recipe "<strong>@Title</strong>" has been added.</p>
        <a href="recipes/@Category.ToLower()" class="btn btn-primary">View in @Category</a>
        <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Title" placeholder="e.g. Grandma's Apple Pie" />
            <ValidationMessage For="() => Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Category">
                <option value="">-- Select a category --</option>
                <option value="Breakfast">Breakfast</option>
                <option value="Lunch">Lunch</option>
                <option value="Dinner">Dinner</option>
                <option value="Desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Ingredients"
                           placeholder="2 cups flour&#10;1 cup sugar&#10;..." />
            <ValidationMessage For="() => Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="Steps"
                           placeholder="1. Preheat oven to 350°F&#10;2. Mix ingredients..." />
            <ValidationMessage For="() => Steps" />
        </div>

        <button type="submit" class="btn btn-primary" disabled="@(!IsValid)">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private string Title { get; set; } = string.Empty;
    private string Category { get; set; } = string.Empty;
    private string Ingredients { get; set; } = string.Empty;
    private string Steps { get; set; } = string.Empty;
    private bool Submitted { get; set; }

    private bool IsValid => !string.IsNullOrWhiteSpace(Title)
                         && !string.IsNullOrWhiteSpace(Category)
                         && !string.IsNullOrWhiteSpace(Ingredients)
                         && !string.IsNullOrWhiteSpace(Steps);

    private void HandleSubmit()
    {
        if (!IsValid) return;

        RecipeService.AddRecipe(Title, Category, Ingredients, Steps);
        Submitted = true;
    }

    private void Reset()
    {
        Title = string.Empty;
        Category = string.Empty;
        Ingredients = string.Empty;
        Steps = string.Empty;
        Submitted = false;
    }
}

